INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd0e20a5a-01d6-4981-b782-da1a78512f06',
  '00000000-0000-0000-0000-000000000001',
  $escape$snyk - Securing Your Dependencies Against OWASP Top 10$escape$,
  $escape$Snyk's vulnerability database contains numerous threats from OWASP Top 10. To secure dependencies, monitor vulnerabilities in your open-source libraries and packages. Use snyk test to scan your project and identify potential security risks such as SQL injection, cross-site scripting (XSS), and security misconfiguration. For instance, if a library is vulnerable to SQL injection, Snyk's test will flag it and recommend a patch. This ensures that your application remains secure against common web application vulnerabilities. To further harden your application, enable snyk monitor to track new vulnerabilities as they emerge.$escape$,
  NULL,
  NULL,
