INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '53c53cda-a312-404c-be56-d71f46bb9528',
  '00000000-0000-0000-0000-000000000001',
  $escape$snyk: Shielding Your Apps from SQL Injection with Parameterized Queries and ORMs$escape$,
  $escape$When using Snyk's Vulnerability Database, SQL Injection vulnerabilities often surface due to unparameterized queries. To mitigate this, use parameterized queries in your Snyk-based applications. Snyk recommends employing Object-Relational Mapping (ORM) tools like Snyk's own ORM, which automatically parameterizes queries. You can also utilize Snyk's Open Source Security testing to identify SQL Injection vulnerabilities and apply fixes. For example, with Snyk's CLI, you can run `snyk test` to detect vulnerabilities and `snyk apply` to apply fixes.$escape$,
  $escape$const db = require('snyk-orm');
const query = 'SELECT * FROM users WHERE email = :email';
const params = { email: 'john.doe@example.com' };
db.query(query, params).then((results) => { console.log(results); });$escape$,
  $escape$javascript$escape$,
