INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'dc2ce99c-a4c6-4268-b73a-8b11dfa8fd84',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snyk: Unlocking SonarQube Quality Gates with Snyk's API$escape$,
  $escape$Snyk's API allows you to integrate SonarQube quality gates directly into your CI/CD pipeline. By doing so, you can ensure that only high-quality codebase is deployed to production. To achieve this, create a Snyk project and retrieve the SonarQube quality gate ID. Then, use the Snyk API to create a new quality gate configuration and link it to your SonarQube instance. Finally, use the Snyk API to trigger the quality gate and receive the results in your pipeline.$escape$,
  $escape$snyk login
snyk project init
snyk config sonarqube quality-gate create -h
snyk config sonarqube quality-gate link -h
snyk config sonarqube quality-gate trigger -h$escape$,
  $escape$bash$escape$,
