INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c25b3be4-260b-4b60-b889-b5a673e117fa',
  '00000000-0000-0000-0000-000000000001',
  $escape$Snyk — Fix Vulnerable Dependencies in Pull Requests with Snyk CLI$escape$,
  $escape$Use Snyk CLI to scan your repository and create a Snyk project. Then, configure Snyk to monitor your project and trigger automatic vulnerability tests for pull requests. With the Snyk CLI, you can also scan dependencies in Docker containers and Infrastructure-as-Code (IaC) files. To fix vulnerabilities in a pull request, run `snyk test` to identify issues, and `snyk fix` to apply patches. You can also use the Snyk CLI to generate a report on the security vulnerabilities in your project.$escape$,
  $escape$snyk test
snyk fix
git add .
git commit -m ': fix vulnerabilities'
git push$escape$,
  $escape$bash$escape$,
